processing.text:

if @@admin = 0 and @type = '1' begin
  if @@sysDatabaseName.dbo.FastBusiness$System$GetAuthorize(@@admin, @@userID, 'Contract', 'Edit') = 0 select @type = '0'
end

declare @message nvarchar(4000), @q nvarchar(4000), @duplicate nvarchar(4000), @irregular nvarchar(4000), @field varchar(32), @irregularChars varchar(128), @r int

select @irregularChars = &IrregularValue;
select @duplicate = case @@language when 'v' then N'Giá trị tại ô <span class="Highlight">%invalidCell</span> &Contract.Nested.Message.v;.' else 'The value of cell <span class="Highlight">%invalidCell</span> is &Contract.Nested.Message.e;.' end
select @irregular = case @@language when 'v' then N'Giá trị tại ô <span class="Highlight">%invalidCell</span> có chứa các ký tự: ' + @irregularChars else 'The value of cell <span class="Highlight">%invalidCell</span> contains any of the following characters: ' + @irregularChars  end

-- Check
create index i on @@table (ma_hd)

if @type = '0' delete @@table where ma_hd in (select ma_hd from dmhd)

select @field = 'ma_hd', @r = min(stt) from @@table where ma_hd like '%[' + @irregularChars + ']%'&Irregular;

-- Checking
&Checking;

select a.* into #k from @@table a join dmhd b on a.ma_hd = b.ma_hd
delete @@table where ma_hd in (select ma_hd from #k)
if @type = '1' select @field = 'ma_hd', @r = min(stt) from #k where ma_hd not in (select ma_hd from dmhd)&Error;

--
select @field = 'ma_hd'
&Contract.Nested.Key.b;
  select @q = 'select top 1 @r = a.stt from @@table a, @@table b with (index(i)) where a.ma_hd <> b.ma_hd and a.ma_hd like rtrim(b.ma_hd) + ''%'''
  exec sp_executesql @q, N'@r int output', @r = @r output&Duplicate;
  select @q = 'select top 1 @r = a.stt from @@table a with (index(i)), dmhd b with (index(PK_dmhd)) where a.ma_hd like rtrim(b.ma_hd) + ''%'''
  exec sp_executesql @q, N'@r int output', @r = @r output&Duplicate;
  select @q = 'select top 1 @r = b.stt from dmhd a with (index(PK_dmhd)), @@table b with (index(i)) where a.ma_hd like rtrim(b.ma_hd) + ''%'''
  exec sp_executesql @q, N'@r int output', @r = @r output&Duplicate;
end
-- Insert
&Inserting;

-- Update
if @type = '1' begin &Updating; end
